				if err != nil {
					t.Fatalf("Failed to clean up test storage: %v", err)
				}

				account := &datamodel.Account{
					BaseModel: datamodel.BaseModel{UUID: "test-account-uuid"},
					Name:      "test_account",
				}
				err = store.DB().Create(account).Error
